const TEAM_ALIASES: Record<string, string> = {"PHO": "PHX", "BRK": "BKN", "CHO": "CHA", "NOH": "NOP", "NOR": "NOP", "NO": "NOP", "GS": "GSW", "SA": "SAS", "NY": "NYK", "WSH": "WAS", "UTAH": "UTA", "SAN": "SAS"};

/** Normalize any common team abbreviation to the table key (e.g. PHO->PHX). */
export function normalizeTeam(raw: string): string {
  const k = (raw || "").trim().toUpperCase();
  return TEAM_ALIASES[k] ?? k;
}

/** Per-team 2024-25 profile, or undefined if the abbreviation is unknown. */
export function getTeamData(
  abbr: string,
): Partial<Record<TeamStat, number>> | undefined {
  return TEAM_DATA[normalizeTeam(abbr)];
}
